configuration.processScript:
var scoopable = new HashSet<string> { "O", "B", "A", "F", "G", "K", "M" };
var currentSystem = Trigger?["StarSystem"]?.GetValue<string>() ?? "";
var route = NavRoute?["Route"]?.AsArray();

if (route == null || route.Count == 0)
{
    Result["announcement"] = "";
    return;
}

int currentIdx = -1;
for (int i = 0; i < route.Count; i++)
{
    if (route[i]?["StarSystem"]?.GetValue<string>() == currentSystem)
    {
        currentIdx = i;
        break;
    }
}

if (currentIdx < 0 || currentIdx >= route.Count - 1)
{
    Result["announcement"] = "";
    return;
}

int count = 0;
for (int i = currentIdx + 1; i < route.Count; i++)
{
    var starClass = route[i]?["StarClass"]?.GetValue<string>() ?? "";
    var cls = starClass.Length > 0 ? starClass[0].ToString().ToUpperInvariant() : "";
    if (scoopable.Contains(cls)) break;
    count++;
}

Result["announcement"] = count switch
{
    0 => "",
    1 => "The next star is not scoopable, so gas up here.",
    _ => $"The next {count} stars are not scoopable, so gas up here.",
};
